const email = $input.first().json;
const attachments = email.attachments ?? [];

// Cherche une pièce jointe PDF
const pdf = attachments.find(a => 
  a.contentType === 'application/pdf' || 
  (a.filename ?? '').toLowerCase().endsWith('.pdf')
);

if (!pdf) return [];

const base64 = Buffer.from(pdf.content ?? '', 'binary').toString('base64');

return [{ 
  json: { 
    base64, 
    filename: pdf.filename ?? 'facture.pdf',
    from: email.from,
    subject: email.subject,
    date: email.date
  } 
}];

