const claudeResp = $input.first().json;
const emailData = $('Extrait PDF').first().json;
const text = claudeResp.content?.[0]?.text ?? '{}';

let parsed = {};
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch?.[0] ?? '{}');
} catch(e) {
  parsed = { notes: text };
}

parsed.email_from = emailData.from;
parsed.email_subject = emailData.subject;
parsed.email_date = emailData.date;
parsed.filename = emailData.filename;

return [{ json: parsed }];
